zes\":[]},\"space\":{\"unit\":\"%\",\"size\":100,\"sizes\":[]},\"height\":{\"unit\":\"px\",\"size\":450,\"sizes\":[]},\"hover_animation\":\"grow\",\"image_border_border\":\"solid\",\"image_border_width\":{\"unit\":\"px\",\"top\":\"2\",\"right\":\"2\",\"bottom\":\"2\",\"left\":\"2\",\"isLinked\":true}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":true}],\"isInner\":false},{\"id\":\"7d474dd\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"ba05847\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"editor\":\"<p>Os vestidos com estampas florais s\\u00e3o a escolha perfeita para um visual fresco e rom\\u00e2ntico. Essas pe\\u00e7as cl\\u00e1ssicas s\\u00e3o ideais para a primavera e o ver\\u00e3o, trazendo leveza e alegria ao seu guarda-roupa. Com uma variedade de padr\\u00f5es e cores, os vestidos florais podem ser usados em diversas ocasi\\u00f5es, desde um passeio casual at\\u00e9 um evento mais formal. Eles combinam perfeitamente com acess\\u00f3rios neutros ou vibrantes, permitindo infinitas possibilidades de estilo. Adicione um vestido floral \\u00e0 sua cole\\u00e7\\u00e3o e sinta-se radiante em qualquer lugar.<\\/p>\",\"text_color\":\"#000000\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Roboto Serif\",\"typography_font_weight\":\"400\",\"_margin\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"10\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]'),(886,216,'_elementor_page_assets','a:1:{s:6:\"styles\";a:1:{i:0;s:12:\"e-animations\";}}'),(889,217,'_elementor_edit_mode','builder'),(890,217,'_elementor_template_type','wp-page'),(891,217,'_elementor_version','3.23.3'),(892,217,'_wp_page_template','default'),(893,217,'_elementor_data','[{\"id\":\"e594674\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"8a28256\",\"elType\":\"widget\",\"settings\":{\"content_w