custom\",\"typography_font_family\":\"Roboto Serif\",\"typography_font_weight\":\"400\",\"_margin\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"10\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]'),(1145,260,'_elementor_edit_mode','builder'),(1146,260,'_elementor_template_type','wp-page'),(1147,260,'_elementor_version','3.23.3'),(1149,260,'_wp_page_template','default'),(1150,260,'_elementor_data','[{\"id\":\"0251d8c\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"919f0a2\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"editor\":\"<p>Nossos acess\\u00f3rios s\\u00e3o o toque final perfeito para qualquer look. Nossa cole\\u00e7\\u00e3o inclui desde bolsas e cintos elegantes at\\u00e9 joias delicadas e chap\\u00e9us estilosos, oferecendo op\\u00e7\\u00f5es para todas as ocasi\\u00f5es. Cada acess\\u00f3rio \\u00e9 cuidadosamente escolhido para garantir qualidade, durabilidade e design moderno. Explore nossa linha de acess\\u00f3rios e descubra como pequenos detalhes podem transformar seu visual e refletir sua personalidade \\u00fanica.<\\/p>\",\"text_color\":\"#000000\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Roboto Serif\",\"typography_font_weight\":\"400\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]'),(1151,164,'_elementor_page_assets','a:1:{s:6:\"styles\";a:1:{i:0;s:12:\"e-animations\";}}'),(1154,261,'_elementor_edit_mode','builder'),(1155,261,'_elementor_template_type','wp-page'),(1156,261,'_elementor_version','3.23.3'),(1158,262,'_elementor_edit_mode','builder'),(1159,262,'_elementor_template_type','wp-page'),(1160,262,'_elementor_version','3.23.3'),(1162,163,'_wp_page_template','default'),(1163,163,'_elementor_data','[{\"id\":\"e898ad8\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"f4d72c5\",\"elType\":\"widget\",\"settings\":