INSERT INTO `wp_postmeta` VALUES (1566,362,'_elementor_data','[{\"id\":\"74272e4\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"a3cb667\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"editor\":\"<p>Os agasalhos estilosos s\\u00e3o pe\\u00e7as indispens\\u00e1veis para quem deseja enfrentar o frio com eleg\\u00e2ncia e conforto. Dispon\\u00edveis em diversos cortes, tecidos e cores, eles podem transformar um look b\\u00e1sico em uma produ\\u00e7\\u00e3o sofisticada. Casacos de l\\u00e3, jaquetas bomber, trench coats e parkas s\\u00e3o apenas algumas das op\\u00e7\\u00f5es que combinam funcionalidade com design moderno. Al\\u00e9m de aquecer, os agasalhos estilosos permitem in\\u00fameras combina\\u00e7\\u00f5es, sendo perfeitos para ocasi\\u00f5es casuais ou formais. Aposte em pe\\u00e7as de qualidade e corte impec\\u00e1vel para garantir um visual chic e atual.<\\/p>\",\"text_color\":\"#000000\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Roboto Serif\",\"typography_font_weight\":\"400\",\"_margin\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"10\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false},{\"id\":\"c9cc37e\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"962919b\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"title\":\"Casaco de l\\u00e3\",\"align\":\"center\",\"title_color\":\"#000000\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Roboto\",\"typography_font_weight\":\"600\"},\"elements\":[],\"widgetType\":\"heading\"}],\"isInner\":false},{\"id\":\"380f780\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"row\",\"flex_gap\":{\"unit\":\"px\",\"size\":0,\"column\":\"0\",\"row\":\"0\"}},\"elements\":[{\"id\":\"eab5a42\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\",\"content_width\":\