00,\"sizes\":[]},\"height\":{\"unit\":\"px\",\"size\":450,\"sizes\":[]},\"hover_animation\":\"grow\",\"image_border_border\":\"solid\",\"image_border_width\":{\"unit\":\"px\",\"top\":\"2\",\"right\":\"2\",\"bottom\":\"2\",\"left\":\"2\",\"isLinked\":true},\"image\":{\"url\":\"http:\\/\\/10.26.45.27\\/duo_fashion\\/wp-content\\/uploads\\/2024\\/08\\/Prancheta-4-15.png\",\"id\":346,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":true},{\"id\":\"3a32efc\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\",\"content_width\":\"full\",\"width\":{\"unit\":\"%\",\"size\":\"25\"}},\"elements\":[{\"id\":\"b498f12\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"image_size\":\"medium\",\"width\":{\"unit\":\"%\",\"size\":280,\"sizes\":[]},\"space\":{\"unit\":\"%\",\"size\":100,\"sizes\":[]},\"height\":{\"unit\":\"px\",\"size\":450,\"sizes\":[]},\"hover_animation\":\"grow\",\"image_border_border\":\"solid\",\"image_border_width\":{\"unit\":\"px\",\"top\":\"2\",\"right\":\"2\",\"bottom\":\"2\",\"left\":\"2\",\"isLinked\":true},\"image\":{\"url\":\"http:\\/\\/10.26.45.27\\/duo_fashion\\/wp-content\\/uploads\\/2024\\/08\\/Prancheta-2-17.png\",\"id\":344,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":true}],\"isInner\":false},{\"id\":\"4c131ca\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"0d6a983\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"editor\":\"<p>O casaco de l\\u00e3 \\u00e9 uma pe\\u00e7a essencial no guarda-roupa de inverno, conhecida por sua capacidade de proporcionar calor e conforto. Feito de materiais naturais como a l\\u00e3 de ovelha, esses casacos s\\u00e3o ideais para dias frios, pois ret\\u00eam o calor corporal. Dispon\\u00edveis em uma variedade de estilos e cortes, os casacos de l\\u00e3 s\\u00e3o vers\\u00e1teis, podendo ser usados tanto