s ou at\\u00e9 mesmo usar por baixo de blazers. As camisetas V-neck s\\u00e3o perfeitas para quem busca conforto e um toque de eleg\\u00e2ncia no dia a dia.<\\/p>\",\"text_color\":\"#000000\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Roboto Serif\",\"typography_font_weight\":\"400\",\"_margin\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"10\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false},{\"id\":\"3bfa6e1\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\"},\"elements\":[{\"id\":\"572188c\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"title\":\"Camisetas Tie-Dye\",\"align\":\"center\"},\"elements\":[],\"widgetType\":\"heading\"}],\"isInner\":false},{\"id\":\"8cd24a0\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"row\",\"flex_gap\":{\"unit\":\"px\",\"size\":0,\"column\":\"0\",\"row\":\"0\"}},\"elements\":[{\"id\":\"89c351f\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\",\"content_width\":\"full\",\"width\":{\"unit\":\"%\",\"size\":\"25\"}},\"elements\":[{\"id\":\"738571c\",\"elType\":\"widget\",\"settings\":{\"content_width\":\"full\",\"image_size\":\"medium\",\"width\":{\"unit\":\"px\",\"size\":280,\"sizes\":[]},\"width_tablet\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"width_mobile\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"space\":{\"unit\":\"%\",\"size\":100,\"sizes\":[]},\"height\":{\"unit\":\"px\",\"size\":450,\"sizes\":[]},\"image\":{\"url\":\"http:\\/\\/10.26.45.27\\/duo_fashion\\/wp-content\\/uploads\\/2024\\/08\\/Prancheta-1-7.png\",\"id\":274,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"hover_animation\":\"grow\",\"image_border_border\":\"solid\",\"image_border_radius\":{\"unit\":\"px\",\"top\":\"2\",\"right\":\"2\",\"bottom\":\"2\",\"left\":\"2\",\"isLinked\":true}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":true},{\"id\":\"5505eca\",\"elType\":\"contai