e inova\\u00e7\\u00e3o e charme.<\\/p>\\t\\t\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t<div class=\\\"elementor-element elementor-element-c487df6 e-flex e-con-boxed e-con e-parent\\\" data-id=\\\"c487df6\\\" data-element_type=\\\"container\\\">\\n\\t\\t\\t\\t\\t<div class=\\\"e-con-inner\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-element elementor-element-d8b80f3 elementor-widget elementor-widget-heading\\\" data-id=\\\"d8b80f3\\\" data-element_type=\\\"widget\\\" data-widget_type=\\\"heading.default\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-widget-container\\\">\\n\\t\\t\\t<h2 class=\\\"elementor-heading-title elementor-size-default\\\">Vestidos estampa florais<\\/h2>\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t<div class=\\\"elementor-element elementor-element-2e7bba9 e-flex e-con-boxed e-con e-parent\\\" data-id=\\\"2e7bba9\\\" data-element_type=\\\"container\\\">\\n\\t\\t\\t\\t\\t<div class=\\\"e-con-inner\\\">\\n\\t\\t<div class=\\\"elementor-element elementor-element-aa1e7be e-con-full e-flex e-con e-child\\\" data-id=\\\"aa1e7be\\\" data-element_type=\\\"container\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-element elementor-element-3888743 elementor-widget elementor-widget-image\\\" data-id=\\\"3888743\\\" data-element_type=\\\"widget\\\" data-widget_type=\\\"image.default\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-widget-container\\\">\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<img width=\\\"187\\\" height=\\\"300\\\" src=\\\"http:\\/\\/10.26.45.27\\/duo_fashion\\/wp-content\\/uploads\\/2024\\/08\\/Prancheta-1-2.png\\\" class=\\\"elementor-animation-grow attachment-medium size-medium wp-image-206\\\" alt=\\\"\\\" \\/>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t<div class=\\\"elementor-element elementor-element-b41fe86 e-con-full e-flex e-con e-child\\\" data-id=\\\"b41fe86\\\" data-element_t