\\\" data-widget_type=\\\"heading.default\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-widget-container\\\">\\n\\t\\t\\t<h2 class=\\\"elementor-heading-title elementor-size-default\\\">Blazers oversized<\\/h2>\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t<div class=\\\"elementor-element elementor-element-ea93047 e-flex e-con-boxed e-con e-parent\\\" data-id=\\\"ea93047\\\" data-element_type=\\\"container\\\">\\n\\t\\t\\t\\t\\t<div class=\\\"e-con-inner\\\">\\n\\t\\t<div class=\\\"elementor-element elementor-element-2d70fc1 e-con-full e-flex e-con e-child\\\" data-id=\\\"2d70fc1\\\" data-element_type=\\\"container\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-element elementor-element-e0a8ddb elementor-widget elementor-widget-image\\\" data-id=\\\"e0a8ddb\\\" data-element_type=\\\"widget\\\" data-widget_type=\\\"image.default\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-widget-container\\\">\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<img width=\\\"187\\\" height=\\\"300\\\" src=\\\"http:\\/\\/10.26.45.27\\/duo_fashion\\/wp-content\\/uploads\\/2024\\/08\\/Prancheta-1-3.png\\\" class=\\\"elementor-animation-grow attachment-medium size-medium wp-image-224\\\" alt=\\\"\\\" \\/>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t\\t\\t<\\/div>\\n\\t\\t<div class=\\\"elementor-element elementor-element-79856d7 e-con-full e-flex e-con e-child\\\" data-id=\\\"79856d7\\\" data-element_type=\\\"container\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-element elementor-element-8049e97 elementor-widget elementor-widget-image\\\" data-id=\\\"8049e97\\\" data-element_type=\\\"widget\\\" data-widget_type=\\\"image.default\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-widget-container\\\">\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<img width=\\\"187\\\" height=\\\"300\\\" src=\\\"http:\\/\\/10.26.45.27\\/duo_fashion\\/wp-content\\/uploads\\/2024\\/08\\/Prancheta-2-4.png\\\" class=\\\"elementor-animation-grow attachment